	match, err := regexp.MatchString("^(extgroupid-[^@]+@[^@]+|anyUE)$", ueGroupId)
	if !match {
		problemDetail := models.ProblemDetails{
			Title:  "Invalid parameter",
			Status: http.StatusBadRequest,
